sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

	var ajax  = new GlideAjax('ClientTaskTemplateHelpers');
	ajax.addParam('sysparm_name', 'getTemplateDefaultPrimaryAssignee');
	ajax.addParam('sysparm_sys_id', g_form.getUniqueValue());
	ajax.addParam('sysparm_table', g_form.getTableName());
	ajax.addParam('sysparm_restricted_group', g_form.getValue('u_restricted_group'));
	ajax.addParam('sysparm_assigned_member', g_form.getValue('u_assigned_member'));
	ajax.addParam('sysparm_template', g_form.getUniqueValue());
	ajax.addParam('sysparm_template_level', g_form.getValue('process_level'));	
	ajax.addParam('sysparm_template_ou', g_form.getValue('process_ou'));
	ajax.getXML(f_returnDefaultPrimaryAssignee);
}
function f_returnDefaultPrimaryAssignee(response)
{
		try{
			var defaultPrimaryAssignee = response.responseXML.documentElement.getAttribute("answer");
			if(defaultPrimaryAssignee != ''){
				g_form.setValue('u_primary_assignee',defaultPrimaryAssignee);
			}
		}catch(e){
			jslog(e);
		}	
}
